197→
198→  if (table === "decision") {
199→    const row = await surreal.select<{ summary: string }>(record as RecordId<"decision", string>);
200→    return row?.summary;
201→  }
202→
203→  const row = await surreal.select<{ text: string }>(record as RecordId<"question", string>);
204→  return row?.text;
