  1→import { Link, useMatchRoute } from "@tanstack/react-router";
  2→import type { ConversationSidebarItem, WorkspaceConversationSidebarResponse } from "../../../shared/contracts";
  3→
  4→type WorkspaceSidebarProps = {
  5→  sidebar?: WorkspaceConversationSidebarResponse;
  6→  activeConversationId?: string;
  7→  isLoading: boolean;
  8→  onNewConversation: () => void;
  9→  onSelectConversation: (conversationId: string) => void;
 10→};
 11→
 12→export function WorkspaceSidebar({
 13→  sidebar,
 14→  activeConversationId,
 15→  isLoading,
 16→  onNewConversation,
 17→  onSelectConversation,
 18→}: WorkspaceSidebarProps) {
 19→  const matchRoute = useMatchRoute();
 20→  const isHome = matchRoute({ to: "/" });
 21→  const isGraph = matchRoute({ to: "/graph" });
 22→
 23→  function renderConversationItem(conv: ConversationSidebarItem, depth: number = 0) {
 24→    return (
 25→      <li key={conv.id}>
 26→        <button
 27→          type="button"
 28→          className={`sidebar-item sidebar-conversation-item${conv.id === activeConversationId ? " sidebar-item--active" : ""}${depth > 0 ? " sidebar-conversation-item--branch" : ""}`}
 29→          style={depth > 0 ? { paddingLeft: `${8 + depth * 12}px` } : undefined}
 30→          onClick={() => onSelectConversation(conv.id)}
 31→        >
 32→          {depth > 0 ? "\u21b3 " : ""}{conv.title}
 33→        </button>
 34→        {conv.branches && conv.branches.length > 0 ? (
 35→          <ul className="sidebar-list sidebar-branch-list">
 36→            {conv.branches.map((branch) => renderConversationItem(branch, depth + 1))}
 37→          </ul>
 38→        ) : undefined}
 39→      </li>
 40→    );
 41→  }
 42→
 43→  return (
 44→    <aside className="workspace-sidebar">
 45→      {/* Navigation links */}
 46→      <Link to="/" className={`sidebar-item sidebar-nav-item${isHome ? " sidebar-item--active" : ""}`}>
 47→        Feed
 48→      </Link>
 49→      <Link to="/graph" className={`sidebar-item sidebar-nav-item${isGraph ? " sidebar-item--active" : ""}`}>
 50→        Graph
 51→      </Link>
 52→
 53→      <div className="sidebar-divider" />
 54→
 55→      {/* Projects section */}
 56→      <div className="sidebar-section">
 57→        <div className="sidebar-section-label">Projects</div>
 58→        {sidebar?.groups.map((group) => (
 59→          <Link
 60→            key={group.projectId}
 61→            to="/"
 62→            className={`sidebar-item sidebar-project-item${isHome ? " sidebar-item--active" : ""}`}
 63→          >
 64→            #{group.projectName}
 65→          </Link>
 66→        ))}
 67→      </div>
 68→
 69→      {/* Agents section */}
 70→      <div className="sidebar-section">
 71→        <div className="sidebar-section-label">Agents</div>
 72→        <span className="sidebar-item sidebar-agent-item">@pm</span>
 73→      </div>
 74→
 75→      <div className="sidebar-divider" />
 76→
 77→      {/* Chats section */}
 78→      <div className="sidebar-section sidebar-section--chats">
 79→        <div className="sidebar-section-label">
 80→          Chats
 81→          <button
 82→            type="button"
 83→            className="sidebar-new-chat-btn"
 84→            onClick={onNewConversation}
 85→            disabled={isLoading}
 86→            title="New conversation"
 87→          >
 88→            +
 89→          </button>
 90→        </div>
 91→        {sidebar?.groups.map((group) =>
 92→          group.conversations.length > 0 ? (
 93→            <ul key={group.projectId} className="sidebar-list">
 94→              {group.conversations.map((conv) => renderConversationItem(conv))}
 95→            </ul>
 96→          ) : undefined,
 97→        )}
 98→        {sidebar && sidebar.unlinked.length > 0 ? (
 99→          <ul className="sidebar-list">
100→            {sidebar.unlinked.map((conv) => renderConversationItem(conv))}
101→          </ul>
102→        ) : undefined}
103→      </div>
104→    </aside>
105→  );
106→}
