956→        "SELECT `in`, confidence, extracted_at, evidence, evidence_source, resolved_from, from_text",
957→        "FROM extraction_relation",
958→        "WHERE out = $entity",
959→        "AND (",
960→        "  `in` IN (",
961→        "    SELECT VALUE id",
962→        "    FROM message",
963→        "    WHERE conversation IN (SELECT VALUE id FROM conversation WHERE workspace = $workspace)",
964→        "  )",
965→        "  OR `in` IN (SELECT VALUE id FROM document_chunk WHERE workspace = $workspace)",
966→        "  OR `in` IN (SELECT VALUE id FROM git_commit WHERE workspace = $workspace)",
967→        ")",
968→        "ORDER BY extracted_at DESC",
969→        "LIMIT 40;",
970→      ].join(" "),
971→      {
972→        workspace: input.workspaceRecord,
