  1→import { RecordId, type Surreal } from "surrealdb";
  2→
  3→// --- Shared types ---
  4→
  5→type WorkspaceQueryInput = {
  6→  surreal: Surreal;
  7→  workspaceRecord: RecordId<"workspace", string>;
  8→  limit: number;
  9→};
 10→
 11→type ProjectRow = { id: RecordId<"project", string>; name: string };
 12→
 13→// --- Internal helpers ---
 14→
 15→function toRecordIdString(record: RecordId<string, string>): string {
 16→  return record.id as string;
 17→}
 18→
 19→function toIso(value: string | Date): string {
 20→  return value instanceof Date ? value.toISOString() : new Date(value).toISOString();
 21→}
 22→
 23→async function getWorkspaceProjectRows(
 24→  surreal: Surreal,
 25→  workspaceRecord: RecordId<"workspace", string>,
 26→): Promise<ProjectRow[]> {
 27→  const [rows] = await surreal
 28→    .query<[ProjectRow[]]>(
 29→      "SELECT id, name FROM project WHERE id IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace);",
 30→      { workspace: workspaceRecord },
 31→    )
 32→    .collect<[ProjectRow[]]>();
 33→
 34→  return rows;
 35→}
 36→
 37→function buildWorkspaceScopeClause(_table: "decision" | "question" | "task"): string {
 38→  return "workspace = $workspace";
 39→}
 40→
 41→// --- Blocking tier ---
 42→
 43→export type ProvisionalDecisionRow = {
 44→  id: RecordId<"decision", string>;
 45→  summary: string;
 46→  status: string;
 47→  priority?: string;
 48→  category?: string;
 49→  created_at: string | Date;
 50→  project?: string; // resolved after query
 51→};
 52→
 53→export async function listProvisionalDecisions(
 54→  input: WorkspaceQueryInput,
 55→): Promise<ProvisionalDecisionRow[]> {
 56→  const projects = await getWorkspaceProjectRows(input.surreal, input.workspaceRecord);
 57→  const projectRecords = projects.map((p) => p.id);
 58→  const projectById = new Map(projects.map((p) => [toRecordIdString(p.id), p.name]));
 59→
 60→  const [rows] = await input.surreal
 61→    .query<[
 62→      Array<{
 63→        id: RecordId<"decision", string>;
 64→        summary: string;
 65→        status: string;
 66→        priority?: string;
 67→        category?: string;
 68→        created_at: string | Date;
 69→      }>,
 70→    ]>(
 71→      [
 72→        "SELECT id, summary, status, priority, category, created_at",
 73→        "FROM decision",
 74→        "WHERE status IN ['provisional', 'proposed', 'extracted']",
 75→        `AND ${buildWorkspaceScopeClause("decision")}`,
 76→        "ORDER BY created_at DESC",
 77→        "LIMIT $limit;",
 78→      ].join(" "),
 79→      {
 80→        workspace: input.workspaceRecord,
 81→        projects: projectRecords,
 82→        limit: input.limit,
 83→      },
 84→    )
 85→    .collect<[
 86→      Array<{
 87→        id: RecordId<"decision", string>;
 88→        summary: string;
 89→        status: string;
 90→        priority?: string;
 91→        category?: string;
 92→        created_at: string | Date;
 93→      }>,
 94→    ]>();
 95→
 96→  const results: ProvisionalDecisionRow[] = [];
 97→
 98→  for (const row of rows) {
 99→    const [projectRows] = await input.surreal
100→      .query<[Array<RecordId<"project", string>>]>(
101→        "SELECT VALUE out FROM belongs_to WHERE `in` = $decision AND out IN $projects LIMIT 1;",
102→        { decision: row.id, projects: projectRecords },
103→      )
