 7→type SearchOverlayProps = {
 8→  onClose: () => void;
 9→};
10→
11→export function SearchOverlay({ onClose }: SearchOverlayProps) {
12→  const { results, isSearching, query, setQuery } = useEntitySearch();
13→  const [activeFilter, setActiveFilter] = useState<EntityKind | "all">("all");
14→  const inputRef = useRef<HTMLInputElement>(null);
15→
16→  const filteredResults =
17→    activeFilter === "all"
18→      ? results
19→      : results.filter((r) => r.kind === activeFilter);
20→
21→  useEffect(() => {
22→    inputRef.current?.focus();
23→  }, []);
24→
25→  useEffect(() => {
26→    function handleKeyDown(e: KeyboardEvent) {
27→      if (e.key === "Escape") onClose();
28→    }
29→    document.addEventListener("keydown", handleKeyDown);
30→    return () => document.removeEventListener("keydown", handleKeyDown);
31→  }, [onClose]);
32→
33→  return (
34→    <div className="search-overlay-backdrop" onClick={onClose}>
35→      <div className="search-overlay" onClick={(e) => e.stopPropagation()}>
36→        <div className="search-overlay-header">
37→          <div className="search-input-wrapper">
38→            <input
39→              ref={inputRef}
40→              type="text"
41→              className="search-input"
42→              placeholder="Search entities..."
43→              value={query}
44→              onChange={(e) => setQuery(e.target.value)}
45→            />
46→          </div>
47→          <button type="button" className="search-overlay-close" onClick={onClose}>
48→            ✕
49→          </button>
50→        </div>
51→
52→        <SearchFilters activeFilter={activeFilter} onFilterChange={setActiveFilter} />
53→
54→        <div className="search-overlay-body">
55→          {!query.trim() ? (
56→            <div className="search-empty">
57→              <p>Type to search across decisions, tasks, features, and more.</p>
58→            </div>
59→          ) : isSearching ? (
60→            <div className="search-empty">
61→              <p>Searching...</p>
62→            </div>
63→          ) : filteredResults.length === 0 ? (
64→            <div className="search-empty">
65→              <p>No results found for &ldquo;{query}&rdquo;.</p>
66→            </div>
67→          ) : (
68→            <div className="search-results">
69→              {filteredResults.map((result) => (
70→                <SearchResultCard key={result.id} result={result} onClose={onClose} />
71→              ))}
72→            </div>
73→          )}
74→        </div>
75→      </div>
76→    </div>
77→  );
78→}
