 16→const acceptWorkItemSchema = z.object({
 17→  kind: z.enum(["task", "feature", "project"]),
 18→  title: z.string().min(1),
 19→  rationale: z.string().min(1),
 20→  project: z.string().optional(),
 21→  priority: z.enum(ENTITY_PRIORITIES).optional(),
