 10→export function ChatPage() {
 11→  const onboardingState = useWorkspaceState((s) => s.onboardingState);
 12→  const setSidebarHandlers = useWorkspaceState((s) => s.setSidebarHandlers);
 13→
 14→  // Read conversationId from /chat/$conversationId route (undefined on /chat)
 15→  const matchWithId = useMatch({ from: "/chat/$conversationId", shouldThrow: false });
 16→  const routeConversationId = matchWithId?.params.conversationId;
 17→
 18→  // Read message search param (works on both /chat and /chat/:id)
 19→  const search = useSearch({ strict: false });
 20→  const messageParam = (search as { message?: string })?.message;
 21→
 22→  const chat = useChatSession();
 23→
 24→  // Keep a ref to the latest chat handlers so the effect below doesn't
 25→  // depend on unstable function references.
 26→  const chatRef = useRef(chat);
 27→  chatRef.current = chat;
 28→
 29→  // Register sidebar handlers so the shell sidebar can interact with chat
 30→  useEffect(() => {
 31→    setSidebarHandlers({
 32→      activeConversationId: chat.activeConversationId,
 33→      isLoading: chat.isLoading,
 34→      onNewConversation: () => chatRef.current.newConversation(),
 35→      onSelectConversation: (id: string) => chatRef.current.selectConversation(id),
 36→    });
 37→  }, [chat.activeConversationId, chat.isLoading]);
 38→
 39→  // Cleanup sidebar handlers on unmount
 40→  useEffect(() => {
 41→    return () => {
 42→      setSidebarHandlers(undefined);
 43→    };
 44→  }, []);
 45→
 46→  // Load conversation from URL param on mount/param change
 47→  useEffect(() => {
 48→    if (routeConversationId && routeConversationId !== chat.activeConversationId) {
 49→      chat.selectConversation(routeConversationId);
 50→    }
 51→  }, [routeConversationId]);
 52→
 53→  // Scroll to message from ?message= search param
 54→  useEffect(() => {
 55→    if (!messageParam) return;
 56→
 57→    const timer = setTimeout(() => {
 58→      const element = document.querySelector(`[data-message-id="${CSS.escape(messageParam)}"]`);
 59→      if (element) {
 60→        element.scrollIntoView({ behavior: "smooth", block: "center" });
 61→        element.classList.add("animate-highlight");
 62→        element.addEventListener("animationend", () => {
 63→          element.classList.remove("animate-highlight");
 64→        }, { once: true });
 65→      }
 66→    }, 100);
 67→
 68→    return () => clearTimeout(timer);
 69→  }, [messageParam, chat.messages]);
 70→
 71→  // Auto-scroll to bottom (skip when targeting a specific message)
 72→  const messagesEndRef = useRef<HTMLDivElement>(null);
 73→  useEffect(() => {
 74→    if (messageParam) return;
 75→    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
 76→  }, [chat.messages]);
 77→
 78→  return (
 79→    <section className="chat-page">
 80→      {(chat.discussEntity ?? chat.conversationDiscussEntity) ? (
 81→        <DiscussEntityCard
 82→          entity={(chat.discussEntity ?? chat.conversationDiscussEntity) as DiscussEntitySummary}
 83→        />
 84→      ) : undefined}
 85→
 86→      <div className="chat-messages">
 87→        {chat.messages.map((message) => (
 88→          <div
 89→            key={message.id}
 90→            data-message-id={message.id}
 91→            className={`chat-message chat-message--${message.role}`}
 92→          >
 93→            {message.role === "user" ? (
 94→              <div className="chat-message-label">You</div>
 95→            ) : undefined}
 96→            {message.parts.map((part, i) => {
 97→              if (part.type === "text") {
 98→                return (
 99→                  <div key={i} className="chat-message-text">
100→                    <Markdown components={{ a: EntityLink }}>{part.text}</Markdown>
101→                  </div>
102→                );
103→              }
104→              if (part.type === "reasoning") {
105→                return (
106→                  <details key={i} className="thinking-block">
107→                    <summary>Thinking</summary>
108→                    <pre className="thinking-content">{part.text}</pre>
109→                  </details>
110→                );
111→              }
112→              if (isToolPart(part)) {
113→                const toolPart = part as { type: string; state: string };
114→                return (
115→                  <div key={i} className="chat-tool-invocation">
116→                    <span className="chat-tool-name">{toolPart.type.replace(/^tool-/, "")}</span>
117→                    {toolPart.state === "output-available" ? (
118→                      <span className="chat-tool-status">Done</span>
119→                    ) : (
120→                      <span className="chat-tool-status chat-tool-status--running">Running...</span>
121→                    )}
122→                  </div>
123→                );
124→              }
125→              return undefined;
126→            })}
127→            {message.role === "assistant" && onboardingState === "complete" ? (
128→              <button
129→                type="button"
130→                className="branch-message-btn"
131→                onClick={() => void chat.branchFromMessage(message.id)}
132→                disabled={chat.isLoading || chat.branchingFromId !== undefined}
133→                title="Branch from here"
134→              >
135→                <svg width="16" height="16" viewBox="0 0 16 16" fill="none" xmlns="http://www.w3.org/2000/svg" aria-hidden="true">
136→                  <path d="M5 3v4.5c0 1.1.9 2 2 2h2.5M5 3L3 5M5 3l2 2M11 5v4.5c0 1.1-.9 2-2 2H6.5M11 5l-2-2M11 5l2-2" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
137→                </svg>
138→              </button>
139→            ) : undefined}
140→          </div>
141→        ))}
142→        <div ref={messagesEndRef} />
143→      </div>
144→
145→      {onboardingState === "summary_pending" ? (
146→        <div className="onboarding-action-buttons">
147→          <button
148→            type="button"
149→            disabled={chat.isLoading}
150→            onClick={() =>
151→              chat.sendMessage("Looks good, let's go.", {
152→                onboardingAction: "finalize_onboarding",
153→              })}
154→          >
155→            Looks good, let's go
156→          </button>
157→          <button
158→            type="button"
159→            disabled={chat.isLoading}
160→            onClick={() =>
161→              chat.sendMessage("I want to add more.", {
162→                onboardingAction: "continue_onboarding",
163→              })}
164→          >
165→            I want to add more
166→          </button>
167→        </div>
168→      ) : undefined}
169→
170→      <ChatInput
171→        onSend={chat.sendMessage}
172→        disabled={chat.isLoading}
173→        onStop={chat.stopMessage}
174→        isStreaming={chat.status === "streaming"}
175→      />
176→
177→      {chat.errorMessage ? <p className="error-message">{chat.errorMessage}</p> : undefined}
178→    </section>
179→  );
180→}
181→
182→function isToolPart(part: { type: string }): boolean {
183→  return part.type.startsWith("tool-");
184→}
185→
186→function ChatInput({
187→  onSend,
188→  disabled,
189→  onStop,
190→  isStreaming,
191→}: {
192→  onSend: (text: string) => void;
193→  disabled: boolean;
194→  onStop: () => void;
195→  isStreaming: boolean;
196→}) {
197→  const [input, setInput] = useState("");
198→  const textareaRef = useRef<HTMLTextAreaElement>(null);
199→
200→  function handleSubmit() {
201→    const trimmed = input.trim();
202→    if (!trimmed || disabled) return;
203→    onSend(trimmed);
204→    setInput("");
205→    // Reset textarea height
206→    if (textareaRef.current) {
207→      textareaRef.current.style.height = "auto";
208→    }
209→  }
210→
211→  function handleKeyDown(e: KeyboardEvent<HTMLTextAreaElement>) {
212→    if (e.key === "Enter" && !e.shiftKey) {
213→      e.preventDefault();
214→      handleSubmit();
215→    }
216→  }
217→
218→  // Auto-resize textarea
219→  useEffect(() => {
220→    const textarea = textareaRef.current;
221→    if (!textarea) return;
222→    textarea.style.height = "auto";
223→    textarea.style.height = `${Math.min(textarea.scrollHeight, 200)}px`;
224→  }, [input]);
225→
226→  return (
227→    <div className="chat-input-container">
228→      <textarea
229→        ref={textareaRef}
230→        className="chat-input"
231→        value={input}
232→        onChange={(e) => setInput(e.target.value)}
233→        onKeyDown={handleKeyDown}
234→        placeholder="Discuss tasks, decisions, and questions..."
235→        rows={1}
236→        disabled={disabled && !isStreaming}
237→      />
238→      {isStreaming ? (
239→        <button
240→          type="button"
241→          className="chat-input-btn chat-input-btn--stop"
242→          onClick={onStop}
243→          title="Stop"
244→        >
245→          Stop
246→        </button>
247→      ) : (
248→        <button
249→          type="button"
250→          className="chat-input-btn chat-input-btn--send"
251→          onClick={handleSubmit}
252→          disabled={disabled || input.trim().length === 0}
253→          title="Send"
254→        >
255→          Send
256→        </button>
257→      )}
258→    </div>
259→  );
260→}
