 1→import { useCallback, useEffect, useRef, useState } from "react";
 2→import type { GovernanceFeedResponse } from "../../shared/contracts";
 3→import { useWorkspaceState } from "../stores/workspace-state";
 4→
 5→const POLL_INTERVAL_MS = 30_000;
 6→
 7→type UseGovernanceFeedReturn = {
 8→  feed: GovernanceFeedResponse | undefined;
 9→  isLoading: boolean;
10→  error: string | undefined;
11→  refresh: () => void;
12→};
13→
14→export function useGovernanceFeed(): UseGovernanceFeedReturn {
15→  const workspaceId = useWorkspaceState((s) => s.workspaceId);
16→  const [feed, setFeed] = useState<GovernanceFeedResponse | undefined>();
17→  const [isLoading, setIsLoading] = useState(false);
18→  const [error, setError] = useState<string | undefined>();
19→  const timerRef = useRef<ReturnType<typeof setInterval>>(undefined);
20→
21→  const fetchFeed = useCallback(async () => {
22→    if (!workspaceId) return;
23→
24→    setIsLoading(true);
25→    setError(undefined);
26→
27→    try {
28→      const response = await fetch(
29→        `/api/workspaces/${encodeURIComponent(workspaceId)}/feed`,
30→      );
31→      if (!response.ok) {
32→        const body = await response.text();
33→        throw new Error(body);
34→      }
35→      const data = (await response.json()) as GovernanceFeedResponse;
36→      setFeed(data);
37→    } catch (err) {
38→      setError(err instanceof Error ? err.message : "Failed to load feed");
39→    } finally {
40→      setIsLoading(false);
41→    }
42→  }, [workspaceId]);
43→
44→  useEffect(() => {
45→    if (!workspaceId) return;
46→
47→    void fetchFeed();
48→
49→    timerRef.current = setInterval(() => {
50→      void fetchFeed();
51→    }, POLL_INTERVAL_MS);
52→
53→    return () => {
54→      if (timerRef.current) {
55→        clearInterval(timerRef.current);
56→      }
57→    };
58→  }, [workspaceId, fetchFeed]);
59→
60→  const refresh = useCallback(() => {
61→    void fetchFeed();
62→  }, [fetchFeed]);
63→
64→  return { feed, isLoading, error, refresh };
65→}
