 1→import { useNavigate } from "@tanstack/react-router";
 2→import type {
 3→  GovernanceFeedAction,
 4→  GovernanceFeedItem,
 5→  GovernanceFeedResponse,
 6→} from "../../../shared/contracts";
 7→import { useWorkspaceState } from "../../stores/workspace-state";
 8→import { useViewState } from "../../stores/view-state";
 9→import { FeedSection } from "./FeedSection";
10→
11→async function executeEntityAction(
12→  workspaceId: string,
13→  entityId: string,
14→  action: string,
15→): Promise<void> {
16→  const response = await fetch(
17→    `/api/entities/${encodeURIComponent(entityId)}/actions?workspaceId=${encodeURIComponent(workspaceId)}`,
18→    {
19→      method: "POST",
20→      headers: { "Content-Type": "application/json" },
21→      body: JSON.stringify({ action }),
22→    },
23→  );
24→  if (!response.ok) {
25→    const text = await response.text();
26→    throw new Error(text);
27→  }
28→}
29→
30→export function GovernanceFeed({
31→  feed,
32→  isLoading,
33→  error,
34→  onRefresh,
35→}: {
36→  feed: GovernanceFeedResponse | undefined;
37→  isLoading: boolean;
38→  error: string | undefined;
39→  onRefresh: () => void;
40→}) {
41→  const workspaceId = useWorkspaceState((s) => s.workspaceId);
42→  const navigateToDiscussEntity = useViewState((s) => s.navigateToDiscussEntity);
43→  const navigate = useNavigate();
44→
45→  async function handleAction(item: GovernanceFeedItem, action: GovernanceFeedAction) {
46→    if (!workspaceId) return;
47→
48→    if (action.action === "discuss") {
49→      navigateToDiscussEntity({
50→        id: item.entityId,
51→        kind: item.entityKind,
52→        name: item.entityName,
53→        ...(item.status ? { status: item.status } : {}),
54→      });
55→      void navigate({ to: "/chat" });
56→      return;
57→    }
58→
59→    await executeEntityAction(workspaceId, item.entityId, action.action);
60→    onRefresh();
61→  }
62→
63→  if (error) {
64→    return (
65→      <div className="feed-error">
66→        <p>{error}</p>
67→        <button type="button" onClick={onRefresh}>Retry</button>
68→      </div>
69→    );
70→  }
71→
72→  if (!feed && isLoading) {
73→    return <p className="feed-loading">Loading governance feed...</p>;
74→  }
75→
76→  if (!feed) return undefined;
77→
78→  const totalItems = feed.blocking.length + feed.review.length + feed.awareness.length;
79→
80→  if (totalItems === 0) {
81→    return (
82→      <div className="feed-empty">
83→        <p>No governance items require attention.</p>
84→      </div>
85→    );
86→  }
87→
88→  return (
89→    <div className="governance-feed">
90→      <FeedSection tier="blocking" items={feed.blocking} onAction={handleAction} />
91→      <FeedSection tier="review" items={feed.review} onAction={handleAction} />
92→      <FeedSection tier="awareness" items={feed.awareness} onAction={handleAction} />
93→    </div>
94→  );
95→}
