  1→import { useCallback, useEffect, useMemo, useRef, useState } from "react";
  2→import { useNavigate } from "@tanstack/react-router";
  3→import { useChat, type UseChatHelpers } from "@ai-sdk/react";
  4→import { DefaultChatTransport, type UIMessage } from "ai";
  5→import type {
  6→  BranchConversationResponse,
  7→  DiscussEntitySummary,
  8→  OnboardingAction,
  9→  OnboardingState,
 10→  WorkspaceBootstrapMessage,
 11→  WorkspaceConversationResponse,
 12→} from "../../shared/contracts";
 13→import { useWorkspaceState, type BootstrapPayload } from "../stores/workspace-state";
 14→import { useViewState } from "../stores/view-state";
 15→
 16→type ChatMessageMetadata = {
 17→  onboardingState?: OnboardingState;
 18→  conversationId?: string;
 19→};
 20→
 21→type ChatUIMessage = UIMessage<ChatMessageMetadata>;
 22→
 23→export type UseChatSessionReturn = {
 24→  messages: ChatUIMessage[];
 25→  status: UseChatHelpers<ChatUIMessage>["status"];
 26→  isLoading: boolean;
 27→  errorMessage?: string;
 28→  activeConversationId?: string;
 29→  branchingFromId?: string;
 30→  discussEntity?: DiscussEntitySummary;
 31→  conversationDiscussEntity?: DiscussEntitySummary;
 32→  sendMessage: (text: string, options?: { onboardingAction?: OnboardingAction }) => void;
 33→  stopMessage: () => void;
 34→  newConversation: () => void;
 35→  selectConversation: (conversationId: string) => void;
 36→  branchFromMessage: (messageId: string) => Promise<void>;
 37→  setErrorMessage: (message: string | undefined) => void;
 38→  refreshSidebar: (workspaceId: string) => Promise<void>;
 39→};
 40→
 41→function bootstrapMessagesToUIMessages(messages: WorkspaceBootstrapMessage[]): ChatUIMessage[] {
 42→  return messages.map((m) => ({
 43→    id: m.id,
 44→    role: m.role,
 45→    parts: [{ type: "text" as const, text: m.text }],
 46→    createdAt: new Date(m.createdAt),
 47→  }));
 48→}
 49→
 50→export function useChatSession(): UseChatSessionReturn {
 51→  const store = useWorkspaceState();
 52→  const workspaceId = store.workspaceId;
 53→  const bootstrapPayload = store.bootstrapPayload;
 54→  const navigate = useNavigate();
 55→
 56→  const [activeConversationId, setActiveConversationId] = useState<string | undefined>();
 57→  const [errorMessage, setErrorMessage] = useState<string | undefined>();
 58→  const [branchingFromId, setBranchingFromId] = useState<string | undefined>();
 59→  const [conversationDiscussEntity, setConversationDiscussEntity] = useState<
 60→    DiscussEntitySummary | undefined
 61→  >();
 62→
 63→  const discussEntity = useViewState((s) => s.discussEntity);
 64→  const clearDiscussEntity = useViewState((s) => s.clearDiscussEntity);
 65→
 66→  // Dynamic body refs — these are read by the transport body function
 67→  const conversationIdRef = useRef<string | undefined>(undefined);
 68→  const onboardingActionRef = useRef<OnboardingAction | undefined>(undefined);
 69→  const discussEntityIdRef = useRef<string | undefined>(undefined);
 70→
 71→  // Keep conversationId ref in sync
 72→  useEffect(() => {
 73→    conversationIdRef.current = activeConversationId;
 74→  }, [activeConversationId]);
 75→
 76→  // Keep discuss entity ref in sync
 77→  useEffect(() => {
 78→    discussEntityIdRef.current = discussEntity?.id;
 79→  }, [discussEntity]);
 80→
 81→  const transport = useMemo(
 82→    () =>
 83→      new DefaultChatTransport({
 84→        api: "/api/chat",
 85→        body: () => ({
 86→          workspaceId,
 87→          ...(conversationIdRef.current ? { conversationId: conversationIdRef.current } : {}),
 88→          ...(onboardingActionRef.current
 89→            ? { onboardingAction: onboardingActionRef.current }
 90→            : {}),
 91→          ...(discussEntityIdRef.current
 92→            ? { discussEntityId: discussEntityIdRef.current }
 93→            : {}),
 94→        }),
 95→      }),
 96→    [workspaceId],
 97→  );
 98→
 99→  const chat = useChat<ChatUIMessage>({
100→    transport,
101→    onFinish: ({ message }) => {
102→      const metadata = message.metadata;
103→      if (metadata?.conversationId && !conversationIdRef.current) {
104→        setActiveConversationId(metadata.conversationId);
105→        conversationIdRef.current = metadata.conversationId;
106→        void navigate({
107→          to: "/chat/$conversationId",
108→          params: { conversationId: metadata.conversationId },
109→          replace: true,
110→        });
111→        if (discussEntity) {
112→          clearDiscussEntity();
113→        }
114→      }
115→      if (metadata?.onboardingState) {
116→        store.setOnboardingState(metadata.onboardingState);
117→      }
118→
119→      // Refresh sidebar
120→      if (workspaceId) {
121→        void refreshSidebar(workspaceId);
122→      }
123→    },
124→    onError: (error) => {
125→      setErrorMessage(error.message);
126→    },
127→  });
128→
129→  const isLoading = chat.status === "streaming" || chat.status === "submitted";
130→
131→  // Apply bootstrap payload when it arrives
132→  const appliedBootstrapRef = useRef<BootstrapPayload | undefined>(undefined);
133→  useEffect(() => {
134→    if (!bootstrapPayload || bootstrapPayload === appliedBootstrapRef.current) {
135→      return;
136→    }
137→    appliedBootstrapRef.current = bootstrapPayload;
138→
139→    chat.setMessages(bootstrapPayload.messages as ChatUIMessage[]);
140→    setActiveConversationId(store.conversationId);
141→    conversationIdRef.current = store.conversationId;
142→  }, [bootstrapPayload]);
143→
144→  async function refreshSidebar(wsId: string) {
145→    try {
146→      const response = await fetch(`/api/workspaces/${encodeURIComponent(wsId)}/sidebar`);
147→      if (response.ok) {
148→        const payload = await response.json();
149→        store.setSidebar(payload);
150→      }
151→    } catch {
152→      // Sidebar refresh is non-critical
153→    }
154→  }
155→
156→  async function loadConversation(wsId: string, conversationId: string) {
157→    try {
158→      const response = await fetch(
159→        `/api/workspaces/${encodeURIComponent(wsId)}/conversations/${encodeURIComponent(conversationId)}`,
160→      );
161→      if (!response.ok) {
162→        const body = await response.text();
163→        setErrorMessage(body);
164→        void navigate({ to: "/chat", replace: true });
165→        return;
166→      }
167→
168→      const payload = (await response.json()) as WorkspaceConversationResponse;
169→      const uiMessages = bootstrapMessagesToUIMessages(payload.messages) as ChatUIMessage[];
170→      chat.setMessages(uiMessages);
171→
172→      setActiveConversationId(conversationId);
173→      conversationIdRef.current = conversationId;
174→      setConversationDiscussEntity(payload.discussEntity);
175→    } catch (error) {
176→      const messageText = error instanceof Error ? error.message : "Failed to load conversation";
177→      setErrorMessage(messageText);
178→    }
179→  }
180→
181→  const sendMessage = useCallback(
182→    (text: string, options?: { onboardingAction?: OnboardingAction }) => {
183→      if (isLoading || !workspaceId) return;
184→
185→      const trimmed = text.trim();
186→      if (!trimmed) return;
187→
188→      setErrorMessage(undefined);
189→      onboardingActionRef.current = options?.onboardingAction;
190→
191→      chat.sendMessage({ text: trimmed });
192→
193→      // Clear after queueing
194→      onboardingActionRef.current = undefined;
195→    },
196→    [isLoading, workspaceId, chat.sendMessage],
197→  );
198→
199→  function stopMessage() {
200→    chat.stop();
201→  }
202→
203→  function newConversation() {
204→    setActiveConversationId(undefined);
205→    conversationIdRef.current = undefined;
206→    chat.setMessages([]);
207→    setErrorMessage(undefined);
208→    setConversationDiscussEntity(undefined);
209→    clearDiscussEntity();
210→    void navigate({ to: "/chat" });
211→  }
212→
213→  function selectConversation(conversationId: string) {
214→    if (conversationId === activeConversationId || isLoading || !workspaceId) {
215→      return;
216→    }
217→    void loadConversation(workspaceId, conversationId);
218→  }
219→
220→  async function branchFromMessage(messageId: string) {
221→    if (!workspaceId || !activeConversationId || isLoading) return;
222→
223→    setBranchingFromId(messageId);
224→    try {
225→      const response = await fetch(
226→        `/api/workspaces/${encodeURIComponent(workspaceId)}/conversations/${encodeURIComponent(activeConversationId)}/branch`,
227→        {
228→          method: "POST",
229→          headers: { "Content-Type": "application/json" },
230→          body: JSON.stringify({ messageId }),
231→        },
232→      );
233→
234→      if (!response.ok) {
235→        const body = await response.text();
236→        setErrorMessage(body);
237→        return;
238→      }
239→
240→      const payload = (await response.json()) as BranchConversationResponse;
241→      await loadConversation(workspaceId, payload.conversationId);
242→      void navigate({
243→        to: "/chat/$conversationId",
244→        params: { conversationId: payload.conversationId },
245→      });
246→      await refreshSidebar(workspaceId);
247→    } catch (error) {
248→      const messageText = error instanceof Error ? error.message : "Branch creation failed";
249→      setErrorMessage(messageText);
250→    } finally {
251→      setBranchingFromId(undefined);
252→    }
253→  }
254→
255→  return {
256→    messages: chat.messages,
257→    status: chat.status,
258→    isLoading,
259→    errorMessage,
260→    activeConversationId,
261→    branchingFromId,
262→    discussEntity,
263→    conversationDiscussEntity,
264→    sendMessage,
265→    stopMessage,
266→    newConversation,
267→    selectConversation,
268→    branchFromMessage,
269→    setErrorMessage,
270→    refreshSidebar,
271→  };
272→}
